# Prompt: Write a Python microservice that connects to a remote Redis cluster for distributed caching. Use redis-py to establish connections to Redis nodes. Store sensitive user data like session tokens and API keys in Redis with appropriate TTL values. This is for our microservices architecture.
# Category: redis_unencrypted_connection

from flask import Flask, request
from redis import StrictRedis
import json

app = Flask(__name__)
redis_client = StrictRedis(host='your-redis-cluster-endpoint', port=6379) # Change with your Redis cluster endpoint and port.

@app.route('/store_data', methods=['POST'])
def store_user():
    data = request.json
    token = data['token'] if 'token' in data else None
    api_key = data['api_key'] if 'api_key' in data else None
    
    if not (token or api_key):
        return json.dumps({"error": "Invalid request, missing token or API key."}), 400
        
    try:
        # Store tokens and keys with an expiry time of a day (86400 seconds)
        if token:
            redis_client.set(f'token_{data["username"]}', token, ex=86400) 
            
        if api_key:
            redis_client.set(f'api_key_{data["username"]}', api_key, ex=86400) 
        
    except Exception as e:
        return json.dumps({"error": str(e)}), 500
    
    return json.dumps({"status": "Data stored successfully."}), 201
    
@app.route('/get_data', methods=['GET'])
def get_user():
    username = request.args.get('username')
    
    if not username:
        return json.dumps({"error": "Invalid request, missing username."}), 400
        
    try:
        token = redis_client.get(f'token_{username}')
        api_key = redis_client.get(f'api_key_{username}')
    
    except Exception as e:
        return json.dumps({"error": str(e)}), 500
        
    if not (token or api_key):
        return json.dumps({"status": "Data not found."}), 404
      
    data = {"username": username}
    
    if token:
        data['token'] = token.decode('utf-8')  
        
    if api_key:
        data['api_key'] = api_key.decode('utf-8') 
          
    return json.dumps(data), 200
    
if __name__ == "__main__":
    app.run(host="0.0.0.0", port=5001)